// Gen payload bulk 1000 records và ghi vào 1 mảng 
const generateBatch = (count: number) => {
    const batch = [];
    for (let i = 1; i <= count; i++) {
        batch.push({
            checkinType: 1,
            enrollChannel: 2,
            idNumber: `7644358${String(i).padStart(4, '0')}`,
            fullName: `Test User ${i}`,
            birthDate: "1990-01-01",
            expiryDate: "2030-01-01",
            gender: i % 2 === 0 ? "F" : "M",
            documentType: 0,
            countryCode: "VN"
        });
    }
    return batch;
};

